const root = $json.body ?? $json;
let payload = root.data ?? root;
if (Array.isArray(payload)) payload = payload[0];
if (payload?.messages?.[0]) payload = payload.messages[0];
const key = payload?.key;
if (key?.fromMe === true) return [];
const remoteJid = key?.remoteJid || '';
const waDigits = remoteJid.split('@')[0].split(':')[0].replace(/\D/g, '');
if (!waDigits) return [];
const session_id = waDigits;
const msg = payload.message || payload;
let message_type = 'text';
let message_content = '';
let media_url = '';
if (msg.conversation) message_content = String(msg.conversation);
else if (msg.extendedTextMessage?.text) message_content = String(msg.extendedTextMessage.text);
else if (msg.imageMessage) {
  message_type = 'image';
  media_url = String(msg.imageMessage.url || msg.imageMessage.directPath || '');
  message_content = String(msg.imageMessage.caption || '');
} else if (msg.audioMessage || msg.pttMessage) {
  message_type = 'audio';
  const a = msg.audioMessage || msg.pttMessage;
  media_url = String(a.url || a.directPath || '');
}
return [{
  json: {
    session_id,
    contact_phone: '+' + waDigits,
    contact_name: String(payload.pushName || payload.notifyName || ''),
    message_type,
    message_content,
    media_url,
    timestamp: new Date().toISOString(),
    clinic_id: $env.CLINIC_ID || null,
  },
}];

const n = $('Normalize entrada').first().json;
const row = $input.first().json;
const human = row.human_takeover === true;
const t = row.takeover_at ? new Date(row.takeover_at).getTime() : null;
const within60 = t != null && !Number.isNaN(t) && (Date.now() - t < 60000);
if (human && within60) return [];
let needs_reset = false;
if (human && t != null && !within60) needs_reset = true;
return [{
  json: {
    ...n,
    human_takeover: human,
    takeover_at: row.takeover_at,
    session_db_id: row.session_db_id,
    needs_reset,
  },
}];

const base = $('Unir reset').first().json;
const cid = $input.first().json.id;
return [{ json: { ...base, client_id: cid } }];

const base = $('Anexar client_id').first().json;
const hist = $input.first().json.conversation_history || '';
return [{ json: { ...base, conversation_history: hist } }];

const whisper = $input.first().json;
const text = typeof whisper.text === 'string' ? whisper.text : '';
const dl = $('HTTP download áudio').first();
const base = dl.json;
let transcription = text.trim();
if (!transcription) {
  if (!base.media_url) transcription = '(Áudio sem URL de mídia.)';
  else if (!dl.binary?.data) transcription = '(Não foi possível baixar o áudio; confirme URL e cabeçalho apikey da Evolution.)';
  else transcription = '(Não foi possível transcrever o áudio.)';
}
return [{ json: { ...base, transcription } }];

return await (async () => {
  const item = $input.first();
  const base = item.json;
  const caption = String(base.message_content || '').trim();
  const bin = item.binary?.data;
  let image_description = '';
  if (!bin?.data) {
    image_description = caption
      ? 'Legenda do cliente: ' + caption + '\n(Imagem não descarregada — URL ou apikey.)'
      : 'Imagem não disponível para análise.';
    return [{ json: { ...base, image_description } }];
  }
  const mime = bin.mimeType || 'image/jpeg';
  const dataUrl = 'data:' + mime + ';base64,' + bin.data;
  const apiKey = $env.OPENAI_API_KEY;
  const model = $env.OPENAI_VISION_MODEL || 'gpt-4o-mini';
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/chat/completions',
      headers: {
        Authorization: 'Bearer ' + apiKey,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        model,
        max_tokens: 400,
        messages: [
          {
            role: 'user',
            content: [
              {
                type: 'text',
                text:
                  'Descreva de forma breve o conteúdo desta imagem para uma atendente de clínica (PT-BR). Se houver texto legível (exame, receita), resuma.',
              },
              { type: 'image_url', image_url: { url: dataUrl } },
            ],
          },
        ],
      }),
      json: true,
    });
    const desc = res.choices?.[0]?.message?.content || '';
    image_description = caption ? 'Legenda: ' + caption + '\n\nDescrição: ' + desc : desc;
  } catch (e) {
    image_description = caption
      ? 'Legenda: ' + caption + '\n(Não foi possível analisar a imagem automaticamente.)'
      : 'Não foi possível analisar a imagem.';
  }
  return [{ json: { ...base, image_description } }];
})();

const base = $input.first().json;
const hist = base.conversation_history || '';
let current = base.message_content || '';
if (base.message_type === 'image') {
  current = base.image_description || current || '[imagem]';
} else if (base.message_type === 'audio') {
  current = base.transcription || current || '[áudio]';
}
return [{ json: { ...base, conversation_history: hist, current_message: current } }];

