const base = $('Preparar input IA').first().json;
const raw = $input.first().json.choices?.[0]?.message?.content || '';
const needHuman = /\[HUMANO_NECESSÁRIO\]/i.test(raw);
const clean = raw.replace(/\[HUMANO_NECESSÁRIO\]/gi, '').trim();
const partes = clean.split(/\[QUEBRA\]/i).map((s) => s.trim()).filter(Boolean);
if (!partes.length) partes.push(clean || 'Um momento, por favor.');
return [{ json: { ...base, ai_raw: raw, need_human: needHuman, partes, texto_primeiro: partes[0] } }];

return await (async () => {
  const p = $('Parse QUEBRA e humano').first().json;
  const partes = Array.isArray(p.partes) && p.partes.length ? p.partes : ['Um momento, por favor.'];
  const baseUrl = String($env.EVOLUTION_API_BASE || '').replace(/\/$/, '');
  const inst = String($env.EVOLUTION_INSTANCE || '');
  const key = String($env.EVOLUTION_API_KEY || '');
  const num = String(p.session_id || '');
  if (!baseUrl || !inst || !key || !num) {
    return [{ json: { error: 'missing_evolution_env', partes, session_id: num } }];
  }
  const url = `${baseUrl}/message/sendText/${inst}`;
  for (let i = 0; i < partes.length; i++) {
    if (i > 0) {
      await new Promise((r) => setTimeout(r, 1500 + Math.random() * 1000));
    }
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url,
        headers: { apikey: key, 'Content-Type': 'application/json' },
        body: JSON.stringify({ number: num, text: partes[i] }),
        json: true,
      });
    } catch (e) {
      // tenta enviar as partes seguintes
    }
  }
  return [{ json: { sent: partes.length, session_id: num } }];
})();
